const email = $input.first().json;
const fromText = String(email.from || 'Unknown Sender <customer@example.com>');
const fromMatch = fromText.match(/^(.*?)\s*<([^>]+)>$/);
const customerName = (fromMatch?.[1] || fromText.split('@')[0] || 'Unknown Customer').replace(/^['\"]|['\"]$/g, '').trim();
const customerEmail = (fromMatch?.[2] || fromText.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i)?.[0] || 'customer@example.com').trim();
const body = String(email.textPlain || email.textHtml || 'No body provided.').replace(/<[^>]+>/g, ' ').replace(/\s+\n/g, '\n').trim();

return [
  {
    json: {
      customerName: customerName || 'Unknown Customer',
      customerEmail,
      subject: email.subject || 'Inbound email support request',
      body,
      source: 'gmail',
      metadata: {
        n8nExecutionId: $execution.id,
        receivedAt: new Date().toISOString(),
        rawSource: 'email-inbox',
        channel: 'gmail-imap',
        emailFrom: email.from,
        emailTo: email.to,
        emailDate: email.date,
        messageId: email.metadata?.['message-id'] || email.metadata?.messageId,
        routedBy: 'n8n-email-inbox-workflow'
      }
    }
  }
];

const drafted = $input.first().json;
const ticket = drafted.ticket || drafted;
const priority = ticket.priority || 'normal';
const sentiment = ticket.sentiment || 'neutral';
const notifyReviewer = ['high', 'urgent'].includes(priority) || ['frustrated', 'angry'].includes(sentiment);
const reason = notifyReviewer
  ? `Priority ${priority} and sentiment ${sentiment} should notify a human reviewer.`
  : `Priority ${priority} and sentiment ${sentiment} can stay in the normal approval queue.`;

return [
  {
    json: {
      ...drafted,
      reviewRouting: {
        notifyReviewer,
        reason
      }
    }
  }
];
